### React Component for Transformers.js Sentiment Analysis

Source: https://context7.com/huggingface/transformers.js/llms.txt

A React component (`App.jsx`) that integrates with a Transformers.js sentiment analysis Web Worker. It manages the worker lifecycle using `useEffect` and `useRef`, handles user input, sends text to the worker for analysis, and displays the classification results and loading status. This allows for interactive AI-powered features in a React app.

```javascript
// App.jsx
import { useEffect, useState, useRef } from 'react';

function App() {
    const [result, setResult] = useState(null);
    const [loading, setLoading] = useState(false);
    const workerRef = useRef(null);

    useEffect(() => {
        // Create worker on mount
        workerRef.current = new Worker(new URL('./worker.js', import.meta.url), {
            type: 'module'
        });

        // Listen for results
        workerRef.current.onmessage = (e) => {
            setResult(e.data);
            setLoading(false);
        };

        // Cleanup on unmount
        return () => workerRef.current?.terminate();
    }, []);

    const classify = (text) => {
        setLoading(true);
        workerRef.current.postMessage(text);
    };

    return (
        <div>
            <input
                type="text"
                onKeyDown={(e) => {
                    if (e.key === 'Enter') {
                        classify(e.target.value);
                    }
                }}
                placeholder="Enter text to classify"
            />
            {loading && <p>Analyzing...</p>}
            {result && (
                <div>
                    <p>Label: {result[0].label}</p>
                    <p>Score: {(result[0].score * 100).toFixed(2)}%</p>
                </div>
            )}
        </div>
    );
}

export default App;
```

